#Exercise 2
#Now we have a different challenge |p-q|<2^11*N^(1/4) so the inequality change for the following A-sqrt(N)<2^20
#So we need to try scanning for A upwards from sqrt N so that we can find the factorization of N
def factorization(A:int,N:int)->Boolean:
    """
    This function verifies if a given A could give us the factorization of N following the equation A=(p+q)/2 and x=sqrt(A**2-N)
    Args:
        A(int): A is the number we are trying for as a middle point of p and q (we know it exist because both numbers are odds)
        N(int): N is the module
    Returns:
        is_factor(Boolean): we return True in case the value of A gives us a correct factorization and False otherwise
    """
    x=int(math.isqrt(A**2-N))
    #We try to get a proper value for p if it is a factor of N we return true otherwise we return False
    p=A-x
    if N%p==0:
        return True
    return False
#Now, we use the function created to look for the proper value of A

sqrt_N=math.isqrt(N)
for A in range(sqrt_N,sqrt_N+2**20):
    A=A+1 if A*A<N else A
    if factorization(A,N):
        x=int(math.isqrt(A**2-N))
        p=A-x
        print(p)
        break

#Exercise 3
#For the following exercise we need to find the factorization of the module N which satisfies |3p-2q|<N^(1/4) 
#So we define our new A as A=(3p+2q)/2 and for numbers that are big enough we can assume
#That A is in between 3p and 2q and furthermore A is really close to sqrt(6N)
#It can be shown that A^2-6N<sqrt(N)/4 so we can finally show that A-sqrt(6N)<1 and we can use the same idea as in the previous exercises to find the factorization of N

# We work with 2A = 3p + 2q, so (2A)^2 = 9p^2 + 12pq + 4q^2
# (2A)^2 - 24N = (3p - 2q)^2  so that we can ensure that the value of A we are trying is correct by checking if the value of (2A)^2 - 24N is a perfect square
A = math.isqrt(24 * N) + 1

x_sample = A**2 - 24*N
assert x_sample >= 0

x = math.isqrt(x_sample)
assert x*x == x_sample  

# 2A + x = 2*(3p+2q)/2 + (3p-2q) = 3p+2q + 3p-2q = 6p
# so p = (a_ + x) / 6  OR  p = (a_ - x) / 6
p = (A - x) // 6
q = N // p

print("p:", p)

#Exercise 4
#In this challenge we are given a e= 65537 for the RSA algorithm and The ASCII plaintext was encoded using PKCS v1.5 before the RSA function was applied.
#but the separator used here is '0x00', not '0xFF' as in the lecture, and the N is the one of the first eercise so we already now the factorization
Phi_n=(p1-1)*(q1-1)
#Now we need to find the value of d which is the inverse of e mod Phi_n
def extended_eucledian_inverse(A, N):
    t, new_t = 0, 1
    r, new_r = N, A

    while new_r != 0:
        quotient = r // new_r
        t, new_t = new_t, t - quotient * new_t
        r, new_r = new_r, r - quotient * new_r

    if r > 1:
        return None 

    if t < 0:
        t += N

    return t
d=extended_eucledian_inverse(65537, Phi_n)


